(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[3964],{4652:(n,a,s)=>{"use strict";s.r(a),s.d(a,{data:()=>e});const e={key:"v-94330a46",path:"/python/function/",title:"ฟังก์ชัน",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Benefit of Function",slug:"benefit-of-function",children:[]},{level:2,title:"Create new function",slug:"create-new-function",children:[{level:3,title:"Function Name",slug:"function-name",children:[]},{level:3,title:"Parameters",slug:"parameters",children:[]}]},{level:2,title:"Call Function",slug:"call-function",children:[{level:3,title:"Code",slug:"code",children:[]},{level:3,title:"Return Parameter",slug:"return-parameter",children:[]}]}],filePathRelative:"python/function/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1051:(n,a,s)=>{"use strict";s.r(a),s.d(a,{default:()=>d});var e=s(6252);const p=(0,e.Wm)("h1",{id:"ฟังก์ชัน",tabindex:"-1"},[(0,e.Wm)("a",{class:"header-anchor",href:"#ฟังก์ชัน","aria-hidden":"true"},"#"),(0,e.Uk)(" ฟังก์ชัน")],-1),t=(0,e.Wm)("p",null,[(0,e.Uk)('"ฟังก์ชั่น '),(0,e.Wm)("strong",null,"เป็นกลุ่มของโค้ด"),(0,e.Uk)(' ฟังก์ชั่น โดยส่วนใหญ่แล้ว จะรับค่ามาเพื่อคำนวณ และส่งค่าที่คำนวณได้กลับไป โดยฟังก์ชั่นสามารถถูกใช้ได้หลายครั้ง ไม่จำกัดจำนวน และสามารถเรียกจากจุดไหนของโปรแกรมก็ได้"')],-1),o=(0,e.Uk)('"ฟังก์ชั่น '),c=(0,e.Wm)("strong",null,"เป็นการช่วย Debug โปรแกรม",-1),r=(0,e.Uk)(' เนื่องจากว่า เราสามารถรู้ได้ว่า ปัญหาโค้ดนั้น อยู่ที่บรรทัดใดของโปรแกรม นั่นหมายความว่า ถ้าเรารู้ว่าปัญหาอยู่ที่ฟังก์ชั่นนี้ เราก็สามารถเข้าไปแก้เพียงฟังก์ชั่นนั้นๆ ได้ในทันที ไม่ต้องมานั่งหาทั้งโปรแกรม " - '),l={href:"http://www.cs.utah.edu/~germain/PPS/Topics/function.html",target:"_blank",rel:"noopener noreferrer"},u=(0,e.Uk)("Utah University"),i=(0,e.uE)('<h2 id="benefit-of-function" tabindex="-1"><a class="header-anchor" href="#benefit-of-function" aria-hidden="true">#</a> Benefit of Function</h2><ol><li>น้องสามารถใช้กลุ่มโค้ดนั้นใหม่ได้ ไม่จำเป็นต้องเขียนใหม่ๆ หรือ copy มันซ้ำๆ (Encapsulation)</li><li>น้องสามารถระบุว่าส่วนไหนของโปรแกรมมันพัง ทำให้น้องต้องไปมองการแก้ไขได้ตรงจุดมากขึ้น</li></ol><p>น้องอาจจะยังไม่เก็ทเท่าไหร่ พี่ก็จะแสดง code ให้ดูครับ</p><p>ตัวอย่างโค้ดที่ไม่ใช้ฟังกชัน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token number">12</span>           <span class="token comment"># แจกแจงตัวแปร 1</span>\nvar2 <span class="token operator">=</span> <span class="token number">24</span>           <span class="token comment"># แจกแจงตัวแปร 1</span>\nvar3 <span class="token operator">=</span> var1 <span class="token operator">+</span> var2  <span class="token comment"># คำนวณเลข</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1 <span class="token operator">+</span> var2<span class="token punctuation">)</span>  <span class="token comment"># คำนวณเลข</span>\n\nvar1 <span class="token operator">=</span> <span class="token number">45</span>           <span class="token comment"># แจกแจงตัวแปร 2</span>\nvar2 <span class="token operator">=</span> <span class="token number">725</span>          <span class="token comment"># แจกแจงตัวแปร 2</span>\nvar3 <span class="token operator">=</span> var1 <span class="token operator">+</span> var2  <span class="token comment"># คำนวณเลข</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1 <span class="token operator">+</span> var2<span class="token punctuation">)</span>  <span class="token comment"># คำนวณเลข</span>\n\nvar1 <span class="token operator">=</span> <span class="token number">27</span>           <span class="token comment"># แจกแจงตัวแปร 3</span>\nvar2 <span class="token operator">=</span> <span class="token number">83</span>           <span class="token comment"># แจกแจงตัวแปร 3</span>\nvar3 <span class="token operator">=</span> var1 <span class="token operator">+</span> var2  <span class="token comment"># คำนวณเลข</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1 <span class="token operator">+</span> var2<span class="token punctuation">)</span>  <span class="token comment"># คำนวณเลข</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>และเมื่อพี่มงเอา code ด้านบนมาเปลี่ยนแปลง เพื่อใช้ฟังก์ชั่น ก็จะเป็นแบบนี้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    adder<span class="token punctuation">(</span><span class="token number">12</span><span class="token punctuation">,</span> <span class="token number">24</span><span class="token punctuation">)</span>       <span class="token comment"># แจกแจงตัวแปร 1 + เรียกตัวคำนวณ adder</span>\n    adder<span class="token punctuation">(</span><span class="token number">45</span><span class="token punctuation">,</span> <span class="token number">725</span><span class="token punctuation">)</span>      <span class="token comment"># แจกแจงตัวแปร 2 + เรียกตัวคำนวณ adder</span>\n    adder<span class="token punctuation">(</span><span class="token number">27</span><span class="token punctuation">,</span> <span class="token number">83</span><span class="token punctuation">)</span>       <span class="token comment"># แจกแจงตัวแปร 3 + เรียกตัวคำนวณ adder</span>\n\n<span class="token keyword">def</span> <span class="token function">adder</span><span class="token punctuation">(</span>var1<span class="token punctuation">,</span> var2<span class="token punctuation">)</span><span class="token punctuation">:</span>\n    var3 <span class="token operator">=</span> var1 <span class="token operator">+</span> var2  <span class="token comment"># คำนวณเลข</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span>var3<span class="token punctuation">)</span>         <span class="token comment"># คำนวณเลข</span>\n\nmain<span class="token punctuation">(</span><span class="token punctuation">)</span>                  <span class="token comment"># เรียกฟังก์ชัน main</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>เห็นหรือเปล่าครับ ว่าน้องๆจะอ่านด้านล่างได้ง่ายกว่า (ถ้าน้องเข้าใจมันอ่ะนะ) และหากว่าอนาคต น้องอยากใช้ฟังก์ชันอีก ก็สามารถเรียกได้เลย ไม่ต้องทำการก้อปแปะโค้ดอีก</p><p>สำหรับหลักการเขียนนั้น ก็อ่านต่อเลยจ้า</p><h2 id="create-new-function" tabindex="-1"><a class="header-anchor" href="#create-new-function" aria-hidden="true">#</a> Create new function</h2><p>การสร้าง function ใหม่นั้น ง่ายมากๆเลยครับ​ โดยก็ต้องมีหลักการเขียนอ่ะเนอะ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">kumamon</span><span class="token punctuation">(</span>value_a<span class="token punctuation">,</span> value_b<span class="token punctuation">)</span><span class="token punctuation">:</span>\n    result <span class="token operator">=</span> value_a <span class="token operator">+</span> value_b <span class="token operator">+</span> <span class="token number">12</span>\n    <span class="token keyword">return</span> result\n\nkumamon<span class="token punctuation">(</span><span class="token number">1112</span><span class="token punctuation">,</span> <span class="token number">1669</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>หลักๆ ของ Function นั้น ก็จะมีองค์ประกอบอยู่่ 4 จุดนั่นคือ</p><ol><li>ชื่อฟังก์ชั่น (Function Name)</li><li>ตัวแปรที่จะเก็บค่าที่ได้รับมา (Parameter)</li><li>โค้ดที่น้องต้องการให้มันทำงาน เมื่อมีการเรียกฟังก์ชั่นนั้น</li><li>ค่าที่น้องจะคืนให้ (return parameter)</li></ol><h3 id="function-name" tabindex="-1"><a class="header-anchor" href="#function-name" aria-hidden="true">#</a> Function Name</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> kumamon\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>การสร้างฟังก์ชันใหม่ ก็จะเรื่มด้วย <code>def</code> ตามด้วยชื่อฟังกชั่น (ตามที่น้องอยากจะเรียกมัน)</p><p>ในตัวอย่างด้านล่าง พี่มงได้ตั้งชื่อฟังก์ชั่นนี้เป็น <code>kumamon()</code><br> ทำให้เมื่อพี่มงต้องการที่จะใช้ฟังกชันนี้ พี่ก็จะเรียกฟังก์ชัน โดยการเขียน <code>kumamon()</code> ไว้ตรงจุดที่พี่มงต้องการเอาไปใช้งาน</p><h3 id="parameters" tabindex="-1"><a class="header-anchor" href="#parameters" aria-hidden="true">#</a> Parameters</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token punctuation">(</span>value_a<span class="token punctuation">,</span> value_b<span class="token punctuation">)</span><span class="token punctuation">:</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>สำหรับ () หลังชื่อฟังกชันนั้น จะเป็นตัวบอกว่าต้องรับตัวแปรอะไร (ศัพท์ทางการ : Parameters) เมื่อมีการเรียก หากว่าพี่มงเขียนชื่อ function ว่า <code>adder(var1, var2)</code> นั่นก็หมายความว่า ถ้าจะเรียกฟังกชันนี้ ก็จำเป็นที่จะต้องให้ตัวแปรมันก่อน โดยการเขียน และการเรียงเหมือนชื่อฟังกชันเลย</p><p>บนตัวอย่างด้านบนสุดนั้น พี่มงได้มีการเรียกฟังกชัน <code>adder()</code> โดยการโยนเลขเข้าไปด้วย นั่นคือ 12 กับ 24 (<code>adder(12, 24)</code>)<br> นั่นหมายความว่า พี่มงได้เรียกฟังกชัน <code>adder(var1, var2)</code> แล้ว และเลข 12 ก็จะไปจัดเก๋็บอยู่ในตัวแปร var1 ทันที เช่นเดียวกันกับเลข 24</p><h2 id="call-function" tabindex="-1"><a class="header-anchor" href="#call-function" aria-hidden="true">#</a> Call Function</h2><p>ง่ายๆเลย โดยการเขียนชื่อฟังก์ชั่น และตามด้วย ()</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>แต่หากว่าน้องๆต้องการใช้ฟังก์ชั่นที่ต้องมี Parameter ก็ต้องทำการให้มันด้วยนะครับ<br> โดยการเขียนตัวแปรที่น้องจะให้มัน ดังนี้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon<span class="token punctuation">(</span><span class="token number">1112</span><span class="token punctuation">,</span> <span class="token number">1669</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>หากสั่งให้มันทำงานแล้ว</p><ul><li>เลข 1112 นั้นก็จะถูกเก็บที่ตัวแปร <code>value_a</code></li><li>และ 1669 ก็จะถูกเก็บไว้ที่ตัวแปร <code>value_b</code></li></ul><p>และก็ทำการเอาไปบวกกับ 12 และคืนผลลัพท์ออกมา ที่มีค่าเท่ากับตัวแปร <code>result</code> นั่นเองครับ</p><h3 id="code" tabindex="-1"><a class="header-anchor" href="#code" aria-hidden="true">#</a> Code</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>result <span class="token operator">=</span> value_a <span class="token operator">+</span> value_b <span class="token operator">+</span> <span class="token number">12</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ส่วนต่อไปคือ code ภายใน function ซึ่ง code ข้างใน function <strong>จะทำงานก็ต่อเมื่อ function ถูกเรียกใช้งาน</strong></p><p>น้องๆจะสังเกตุจากโค้ดด้านบนว่า พี่ได้ทำการกด TAB (เท่ากับการกด SPACE BAR 4 ครั้งของ Python (โดยเรียก tab แบบนี้ว่า Soft Tab)) และพี่ก็จะเขียนโค้ดที่หากว่าฟังกชั่นนี้ทำงาน ก็จะทำการ run โปรแกรมที่อยู่ในบรรทัดที่มีการกด TAB</p><h3 id="return-parameter" tabindex="-1"><a class="header-anchor" href="#return-parameter" aria-hidden="true">#</a> Return Parameter</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">return</span> result\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>เป็นค่าที่น้องจะคืนให้กับตัวที่เรียก function นั้นมาทำงาน ตัวอย่างเช่นฟังก์ชั่น <code>calculator()</code> ได้เรียก <code>adder()</code> เพื่อให้คำนวณการบวกให้หน่อย<br> และเมื่อ <code>adder()</code> คำนวณเสร็จแล้ว ตัว <code>calculator()</code> ก็ดันอยากได้ผลลัพท์การคำนวณชะด้วยสิ</p><p>การคืนค่า parameter กลับไป จะใช้คีย์เวิร์ด <code>return</code> และก็ตามด้วยผลลัพท์ หรือตัวแปรครับ ตามตัวอย่างเลย</p><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>kumamon(1112, 1669)</p><p>ในบรรทัดที่ 5 นั้น มีการเรียกฟังก์ชันที่อยู่นอกฟังก์ชันอื่นๆ<br> ก็เพราะว่า ตัว Python จะไม่รัน code ที่อยู่ใน function ถ้าน้องๆ ไม่ได้เรียกมันมาทำงาน ดังนั้น ถ้าน้องไม่มีการเรียกฟังก์ชันในบรรทัดที่ 5 แล้ว</p><p>ก็เหมือนกับว่าไม่ได้ให้ Python ทำงานอะไรครับ</p></div>',39),d={render:function(n,a){const s=(0,e.up)("OutboundLink");return(0,e.wg)(),(0,e.j4)(e.HY,null,[p,t,(0,e.Wm)("p",null,[o,c,r,(0,e.Wm)("a",l,[u,(0,e.Wm)(s)])]),i],64)}}}}]);